// Build complete payload for DeepSeek API
const input = $input.first().json;

const leadName = input.leadName || 'Lead';
const message = input.message;
const history = input.conversationHistory || [];
const profile = input.currentProfile;
const interests = input.currentInterests || [];

let historyStr = '';
for (const msg of history) {
  const role = msg.role === 'user' ? 'Cliente' : 'Assistente';
  historyStr += `${role}: ${msg.content}\n\n`;
}

let profileStr = '';
if (profile) {
  if (profile.investor_profile) profileStr += `- Perfil: ${profile.investor_profile}\n`;
  if (profile.goal) profileStr += `- Objetivo: ${profile.goal}\n`;
  if (profile.timeline) profileStr += `- Prazo: ${profile.timeline}\n`;
  if (profile.monthly_value) profileStr += `- Valor mensal: R$ ${profile.monthly_value}\n`;
}

let interestsStr = '';
for (const int of interests) {
  interestsStr += `- ${int.interest_type}`;
  if (int.interest_details) interestsStr += `: ${int.interest_details}`;
  interestsStr += '\n';
}

const systemPrompt = `Você é um assistente de qualificação de leads da KEA Wealth Management, uma gestora de patrimônio brasileira.

SEU PAPEL:
- Conduza uma conversa natural e profissional
- Apresente os serviços da KEA conforme o interesse do lead
- Extraia informações qualificadoras de forma natural

REGRAS:
1. Seja cordial e profissional
2. NÃO invente informações sobre a KEA
3. A cada resposta, extraia dados do lead
4. Quando tiver informações suficientes, qualifique o lead

FORMATO DE RESPOSTA:
Você DEVE responder APENAS com um JSON neste formato:\n{\n  "message": "sua resposta amigável para o lead",\n  "stage": "welcome | presentation | investor_profile | financial_goal | contact_info | qualification",\n  "extractedData": {\n    "name": null,\n    "email": null,\n    "investor_profile": null,\n    "experience": null,\n    "goal": null,\n    "timeline": null,\n    "monthly_value": null,\n    "interest": null,\n    "interest_details": null,\n    "allow_contact": null\n  },\n  "qualified": false,\n  "qualificationScore": 0,\n  "action": "continue | generate_proposal | notify_team"\n}\n\nPreencha extractedData SOMENTE com campos que o lead mencionou explicitamente.\nMarque qualified=true APENAS se você já tiver: nome, interesse em algum serviço, e perfil de investidor.\nO qualificationScore é a soma: investor_profile=2pts, monthly_value=3pts, interest=1pt, goal=1pt. Mínimo 4pts para qualificar.\nSe qualified=true e action=generate_proposal, uma proposta será gerada automaticamente!`;

const userPrompt = `Histórico da conversa:\n${historyStr}\n\n---\n\nPerfil atual do lead:\n${profileStr}\n\nInteresses atuais:\n${interestsStr}\n\n---\n\nNova mensagem do lead (${leadName}):\n${message}\n\n---\n\nResponda no formato JSON especificado.`;

return {
  leadId: input.leadId,
  phone: input.phone,
  leadName: leadName,
  deepseekBody: JSON.stringify({
    model: "deepseek-chat",
    temperature: 0.7,
    max_tokens: 1000,
    messages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt }
    ]
  })
};

// Parse the JSON response from DeepSeek HTTP API
const rawResponse = $input.first().json;

let parsed;
try {
  // DeepSeek API returns { choices: [{ message: { content: "..." } }] }
  const content = rawResponse.choices?.[0]?.message?.content || rawResponse.response || rawResponse.output;
  parsed = JSON.parse(content);
} catch (e) {
  // If parsing fails, wrap the text in a basic response
  const text = rawResponse.choices?.[0]?.message?.content || rawResponse.response || 'Desculpe, não entendi. Pode repetir?';
  parsed = {
    message: text,
    stage: 'conversation',
    extractedData: {},
    qualified: false,
    qualificationScore: 0,
    action: 'continue'
  };
}

return {
  message: parsed.message,
  stage: parsed.stage || 'conversation',
  qualified: parsed.qualified || false,
  qualificationScore: parsed.qualificationScore || 0,
  action: parsed.action || 'continue',
  extractedData: parsed.extractedData || {},
  metadata: {
    leadId: $json.leadId,
    phone: $json.phone
  }
};
